function nodeExternals(
	{ context, request }: ExternalItemFunctionData,
	callback: (
		err?: Error,
		result?: ExternalItemValue,
		type?: ExternalsType
	) => void
) {
	if (!/^(\.|\/)/.test(request || "")) {
		return callback(undefined, request);
	}

	callback();
}

function extractRuntimeExportNames(source: string): string[] {
	const names = new Set<string>();

	// ESM bundles end with `export { __webpack_exports__X as X, ... };`
	const esmMatches = source.matchAll(/export\s*\{([^}]+)\}\s*;/g);
	for (const m of esmMatches) {
		for (const part of m[1].split(",")) {
			const trimmed = part.trim();
			if (!trimmed) continue;
			const asMatch = trimmed.match(/\s+as\s+([A-Za-z_$][\w$]*)\s*$/);
			const name = asMatch
				? asMatch[1]
				: trimmed.match(/^([A-Za-z_$][\w$]*)/)?.[1];
			if (name) names.add(name);
		}
	}
	if (names.size > 0) return [...names];

	// Webpack IIFE bundles register entry exports via the *last*
	// `__webpack_require__.d(__webpack_exports__, { ... })` call. In
	// production builds those identifiers get minified (e.g. `r.d(o, {...})`),
	// so match any `<ident>.d(<ident>, { ... })` shape.
	const defMatches = [
		...source.matchAll(
			/\b[A-Za-z_$][\w$]*\.d\([A-Za-z_$][\w$]*,\s*\{([\s\S]*?)\}\)/g
		),
	];
	if (defMatches.length > 0) {
		const last = defMatches[defMatches.length - 1][1];
		for (const m of last.matchAll(/([A-Za-z_$][\w$]*)\s*:/g)) {
			names.add(m[1]);
		}
	}
	return [...names];
}

function renderExternalStub(names: string[], globalName: string): string {
	const sorted = [...names].sort();
	return [
		"// AUTO-GENERATED by ExternalStubPlugin — do not edit.",
		`// Re-exports of globalThis.${globalName} (set by the IIFE bundle).`,
		`const __external = /** @type {any} */ (globalThis).${globalName};`,
		"export const {",
		...sorted.map((n) => `\t${n},`),
		"} = __external;",
		"",
	].join("\n");
}

/**
 * Generates a thin "external" stub that re-exports the entries of a globally
 * assigned bundle (e.g. `self.$scramjet`). Consumers that import the package
 * by its bare name pay zero source size — the stub is just a destructure of
 * the global.
 *
 * The export list is discovered automatically by parsing the already-emitted
 * bundle, so new exports flow through without any manual maintenance.
 */
class ExternalStubPlugin {
	bundleFilename: string;
	stubFilename: string;
	globalName: string;
	outputDir: string;

	constructor(opts: {
		bundleFilename: string;
		stubFilename: string;
		globalName: string;
		outputDir: string;
	}) {
		this.bundleFilename = opts.bundleFilename;
		this.stubFilename = opts.stubFilename;
		this.globalName = opts.globalName;
		this.outputDir = opts.outputDir;
	}

	apply(compiler: WebpackCompiler) {
		compiler.hooks.afterEmit.tap("ExternalStubPlugin", () => {
			const bundlePath = join(this.outputDir, this.bundleFilename);
			const stubPath = join(this.outputDir, this.stubFilename);
			let source: string;
			try {
				source = readFileSync(bundlePath, "utf-8");
			} catch (e: any) {
				console.error(
					`ExternalStubPlugin: cannot read ${bundlePath}: ${e.message}`
				);
				return;
			}

			const names = extractRuntimeExportNames(source);
			if (names.length === 0) {
				console.warn(
					`ExternalStubPlugin: no exports discovered in ${bundlePath}; stub not written`
				);
				return;
			}

			const stub = renderExternalStub(names, this.globalName);
			writeFileSync(stubPath, stub);
			console.log(
				`ExternalStubPlugin: wrote ${this.stubFilename} (${names.length} exports → globalThis.${this.globalName})`
			);
		});
	}
}

// Custom plugin to generate TypeScript declarations
class TypeScriptDeclarationsPlugin {
	dir: string;
	tsconfigName: string;
	useAlias: boolean;
	tempDir: string;

	constructor(
		dir: string,
		tempDir: string,
		tsconfigName: string = "tsconfig.types.json",
		useAlias: boolean = true
	) {
		this.dir = dir;
		this.tempDir = tempDir;
		this.tsconfigName = tsconfigName;
		this.useAlias = useAlias;
	}

	apply(compiler: WebpackCompiler) {
		compiler.hooks.afterEmit.tap("TypeScriptDeclarationsPlugin", () => {
			(async () => {
				try {
					console.log(`Generating TypeScript declarations for ${this.dir}...`);
					try {
						const { stdout, stderr } = await execAsync(
							`pnpm exec tsc --project ${this.tsconfigName}`,
							{ cwd: this.dir }
						);
						if (stdout) console.log(stdout);
						if (stderr && !stderr.includes("TS")) console.error(stderr);
					} catch (tscError: any) {
						// tsc exits with error code if there are TS errors, but still generates files
						// Only log if it's not a TypeScript compilation error
						if (tscError.code !== 2) {
							throw tscError;
						}
						// if (tscError.stdout) console.log(tscError.stdout);
						// if (tscError.stderr) console.warn(tscError.stderr);
					}

					if (this.useAlias) {
						const aliasResult = await execAsync(
							`pnpm exec tsc-alias --project ${this.tsconfigName}`,
							{ cwd: this.dir }
						);
						if (aliasResult.stdout) console.log(aliasResult.stdout);
						if (aliasResult.stderr) console.error(aliasResult.stderr);
					}

					try {
						await execAsync(`rm -rf ${this.tempDir}`, { cwd: this.dir });
					} catch (e) {}

					console.log(
						`TypeScript declarations generated successfully for ${this.dir}`
					);
				} catch (error: any) {
					console.error(
						`Error generating TypeScript declarations for ${this.dir}:`,
						error.message
					);
				}
			})();
		});
	}
}

