export const tsloader = {
	test: /\.ts$/,
	loader: "builtin:swc-loader",
	exclude: ["/node_modules/"],
	options: {
		jsc: {
			parser: {
				syntax: "typescript",
			},
			target: "es2022",
		},
		module: {
			type: "es6",
			strict: false,
			strictMode: false,
		},
	},
	type: "javascript/auto",
};
//TODO: replace this
function deepmerge<T extends any>(target: T, source: Partial<T>): T {
	// this whole function is a hack, ignore all of the type errors
	//@ts-ignore this whole function is a hack 
	const output = { ...target };
	if (isObject(target) && isObject(source)) {
		Object.keys(source).forEach((key) => {
			//@ts-ignore this whole function is a hack 
			if (isObject(source[key])) {
				//@ts-ignore this whole function is a hack 
				if (!(key in target)) Object.assign(output, { [key]: source[key] });
				//@ts-ignore this whole function is a hack 
				else output[key] = deepmerge(target[key], source[key]);
			} else {
				//@ts-ignore this whole function is a hack 
				Object.assign(output, { [key]: source[key] });
			}
		});
	}
	return output;
}

function isObject(item: any): item is Record<string, unknown> {
	return item && typeof item === "object" && !Array.isArray(item);
}
const rsDoctorPlugin = process.env.DEBUG ? new RsdoctorRspackPlugin({
						supports: {
							parseBundle: true,
							banner: true,
						},
					})
				: null
const createGenericConfig = (options: Partial<RspackOptions>) => {
	const def = {
		devtool: "source-map",
		mode: "development" as Mode,
		resolve: {
			extensions: [".ts", ".js"],
		},
		module: {
			rules: [tsloader],
			parser: {
				javascript: {
					overrideStrict: "non-strict",
					dynamicImportMode: "eager",
				},
			},
		},
		plugin: [
			rsDoctorPlugin
		],
		optimization: {
			minimizer: [
				new rspack.SwcJsMinimizerRspackPlugin({
					minimizerOptions: {
						module: options.output?.libraryTarget === "module",
					},
				}),
			],
		},
	};
	return defineConfig(deepmerge<RspackOptions>(def as unknown as RspackOptions, options));
};

type ScramjetBuildConfig = {
	entry: RspackOptions["entry"];
	output: RspackOptions["output"]
	rewriterWasm: string;
	extraConfig?: Partial<RspackOptions>;
	name: string;
}
// Common configuration options for scramjet builds
const createScramjetConfig = (options: ScramjetBuildConfig) => {
	const { entry, output, rewriterWasm, extraConfig = {}, name } = options;

	return createGenericConfig({
		name,
		entry,
		resolve: {
			alias: {
				"@rewriters": join(scramjetdir, "src/shared/rewriters"),
				"@client": join(scramjetdir, "src/client"),
				"@": join(scramjetdir, "src"),
			},
		},
		output,
		plugins: [
			// new TsCheckerRspackPlugin({
			// 	typescript: {
			// 		configFile: resolve(scramjetdir, "tsconfig.json"),
			// 	},
			// }),
			new rspack.ProvidePlugin({
				dbg: [join(scramjetdir, "src/log.ts"), "default"],
			}),
			new rspack.DefinePlugin({
				REWRITERWASM: rewriterWasm,
			}),
			new rspack.DefinePlugin({
				VERSION: JSON.stringify(sjpackagemeta.version),
			}),
			new rspack.DefinePlugin({
				COMMITHASH: (() => {
					try {
						const hash = JSON.stringify(
							execSync("git rev-parse --short HEAD", {
								encoding: "utf-8",
							}).replace(/\r?\n|\r/g, "")
						);

						return hash;
					} catch {
						return JSON.stringify("unknown");
					}
				})(),
			}),
			new rspack.DefinePlugin({
				BUILDDATE: JSON.stringify(new Date().toISOString()),
			}),
		],
		target: "webworker",
		ignoreWarnings: [
			{
				module: /src\/entry\.ts/,
				message:
					/Critical dependency: the request of a dependency is an expression/,
			},
		],
		...extraConfig,
	});
};

